import { useState } from "react";
import emailjs from "emailjs-com";
import React from "react";

const initialState = {
  name: "",
  email: "",
  message: "",
};

export const Contact = (props) => {
  const [{ name, email, message }, setState] = useState(initialState);
  const d = props.data;

  const handleChange = (e) => {
    const { name: field, value } = e.target;
    setState((prevState) => ({ ...prevState, [field]: value }));
  };
  const clearState = () => setState({ ...initialState });

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log(name, email, message);

    // Configure com os IDs da sua conta em https://www.emailjs.com/
    emailjs
      .sendForm(
        "YOUR_SERVICE_ID",
        "YOUR_TEMPLATE_ID",
        e.target,
        "YOUR_PUBLIC_KEY"
      )
      .then(
        (result) => {
          console.log(result.text);
          clearState();
        },
        (error) => {
          console.log(error.text);
        }
      );
  };

  return (
    <div>
      <div id="contact">
        <div className="container">
          <div className="col-md-8">
            <div className="row">
              <div className="section-title">
                <h2>{d ? d.sectionTitle : "Contato"}</h2>
                <p>{d ? d.sectionLead : ""}</p>
              </div>
              <form name="sentMessage" onSubmit={handleSubmit}>
                <div className="row">
                  <div className="col-md-6">
                    <div className="form-group">
                      <input
                        type="text"
                        id="name"
                        name="name"
                        className="form-control"
                        placeholder="Nome completo"
                        required
                        onChange={handleChange}
                      />
                      <p className="help-block text-danger"></p>
                    </div>
                  </div>
                  <div className="col-md-6">
                    <div className="form-group">
                      <input
                        type="email"
                        id="email"
                        name="email"
                        className="form-control"
                        placeholder="E-mail corporativo"
                        required
                        onChange={handleChange}
                      />
                      <p className="help-block text-danger"></p>
                    </div>
                  </div>
                </div>
                <div className="form-group">
                  <textarea
                    name="message"
                    id="message"
                    className="form-control"
                    rows="4"
                    placeholder="Contexto: sistemas atuais, volume de usuários, prazo e resultado esperado."
                    required
                    onChange={handleChange}
                  ></textarea>
                  <p className="help-block text-danger"></p>
                </div>
                <div id="success"></div>
                <button type="submit" className="btn btn-custom btn-lg">
                  Enviar mensagem
                </button>
              </form>
            </div>
          </div>
          <div className="col-md-3 col-md-offset-1 contact-info">
            {d && d.whatsappUrl ? (
              <div className="contact-item">
                <h3>{d.whatsappLabel || "WhatsApp"}</h3>
                <p>
                  <a
                    href={d.whatsappUrl}
                    className="contact-whatsapp-btn"
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    <i className="fa fa-whatsapp" aria-hidden="true"></i>
                    Enviar mensagem no WhatsApp
                  </a>
                </p>
                <p className="contact-whatsapp-num">
                  {d.whatsappDisplay || d.phone}
                </p>
              </div>
            ) : null}
            <div className="contact-item">
              <h3>Informações</h3>
              <p>
                <span>
                  <i className="fa fa-map-marker" aria-hidden="true"></i>{" "}
                  Endereço
                </span>
                {d ? d.address : "Carregando…"}
              </p>
            </div>
            <div className="contact-item">
              <p>
                <span>
                  <i className="fa fa-phone" aria-hidden="true"></i> Telefone
                </span>{" "}
                {d && d.whatsappUrl ? (
                  <a
                    className="contact-phone-link"
                    href={d.whatsappUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    {d.phone}
                  </a>
                ) : (
                  d && d.phone
                )}
              </p>
            </div>
            <div className="contact-item">
              <p>
                <span>
                  <i className="fa fa-envelope-o" aria-hidden="true"></i>{" "}
                  E-mail
                </span>{" "}
                {d ? d.email : ""}
              </p>
            </div>
          </div>
          <div className="col-md-12">
            <div className="row">
              <div className="social">
                <ul>
                  {d && d.linkedin ? (
                    <li>
                      <a
                        href={d.linkedin}
                        target="_blank"
                        rel="noopener noreferrer"
                        aria-label="LinkedIn"
                      >
                        <i className="fa fa-linkedin"></i>
                      </a>
                    </li>
                  ) : null}
                  {d && d.instagram ? (
                    <li>
                      <a
                        href={d.instagram}
                        target="_blank"
                        rel="noopener noreferrer"
                        aria-label="Instagram"
                      >
                        <i className="fa fa-instagram"></i>
                      </a>
                    </li>
                  ) : null}
                </ul>
              </div>
            </div>
          </div>
        </div>
      </div>
      <div id="footer">
        <div className="container text-center">
          <p>
            © {new Date().getFullYear()} 55LAB. Todos os direitos reservados.
          </p>
        </div>
      </div>
    </div>
  );
};
